 1	import * as React from 'react';
 2	import * as ReactDOM from 'react-dom';
 3	import { globalStyle } from 'styles/GlobalStyle';
 4	import { RouterProvider } from 'react-router-dom-v5-compat';
 5	import { rootBasename, router, setRouter } from 'app/History';
 6	import { pathRoutes } from 'routes';
 7	import { App } from 'app/App';
 8	import cssVariables from './styles/variables.module.scss';
 9	import '@patternfly/patternfly/patternfly.css';
10	import '@patternfly/patternfly/patternfly-charts.css';
11	import '@patternfly/patternfly/patternfly-charts-theme-dark.css';
12	import '@patternfly/patternfly/patternfly-addons.css';
13	
14	// Enables ACE editor YAML themes
15	import 'ace-builds/src-noconflict/mode-yaml';
16	import 'ace-builds/src-noconflict/theme-eclipse';
17	import 'ace-builds/src-noconflict/theme-twilight';
18	
19	// Enables the search box for the ACE editor
20	import 'ace-builds/src-noconflict/ext-searchbox';
21	
22	// i18n
23	import './i18n';
24	
25	declare global {
26	  interface Date {
27	    toLocaleStringWithConditionalDate(): string;
28	  }
29	}
30	
31	// eslint-disable-next-line no-extend-native
32	Date.prototype.toLocaleStringWithConditionalDate = function () {
33	  const nowDate = new Date().toLocaleDateString();
34	  const thisDate = this.toLocaleDateString();
35	
36	  return nowDate === thisDate ? this.toLocaleTimeString() : this.toLocaleString();
37	};
38	
39	// Adding global styles and CSS variables to body element
40	document.body.classList.add(cssVariables.style);
41	document.body.classList.add(globalStyle);
42	
43	setRouter([
44	  {
45	    element: <App />,
46	    children: pathRoutes
47	  }
48	]);
49	
50	// redirect to the router basename if the pathname does not include it
51	if (!window.location.pathname.includes(rootBasename)) {
52	  router.navigate(`/${window.location.search}`, { replace: true });
53	}
54	
55	ReactDOM.render(<RouterProvider router={router} />, document.getElementById('root') as HTMLElement);

